(438,145,'alojamiento',23,'The Legendha Sukhothai','El hotel Legendha Sukhothai está situado a 10 minutos del parque histórico de Sukhothai, cuenta con habitaciones decoradas en el típico estilo tailandés en madera de teca y rodeadas de naturaleza. Posee una piscina para relajarse tras la visita al parque histórico.','Provincia de Sukhothai, Tailandia',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'hotel',4,'https://www.travelagentsoft.com/assets/uploads/agencia_1/biblioteca/alojamientos/2025/12/alojamientos_23_imagen_1764747046.jpg','https://www.legendhasukhothai.com/','es',1,'2026-03-12 09:49:16',NULL,0,0,NULL),
